#include "Item.h"using namespace std;void Item::setName(const string &name) {    this->name = name;}void Item::setDescription(const string &descriptions) {    this->description = descriptions;}void Item::setId(const string &id) {    this->id = id;}bool Item::isCheckedOut() const {    return checkedOut;}void Item::checkOut(const string &borrowName, const string &dueDate) {    checkedOut = true;    this->borrowName = borrowName;    this->dueDate = dueDate;}void Item::checkIn() {    checkedOut = false;    borrowName = "";    dueDate = "";}string Item::getName() const {    return name;}string Item::getDescription() const {    return description;}string Item::getId() const {    return id;}string Item::getBorrowName() const {    return borrowName;}string Item::getDueDate() const {    return dueDate;}ostream &operator<<(ostream &out, const Item &item) {    item.print(out);    return out;}